import { Component, OnInit } from '@angular/core';
import html2canvas from 'html2canvas';
import { TranslateService } from '@ngx-translate/core';
@Component({
  selector: 'app-tier-list',
  templateUrl: './tier-list.component.html',
  styleUrls: ['./tier-list.component.scss'],
})
export class TierListComponent  implements OnInit {

  sourceImages = [
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'data:image/jpeg;base64,' },
    { label: '', url: 'data:image/jpeg;base64,' },       
    { label: '', url: 'data:image/jpeg;base64,' }, 
    { label: '', url: 'data:image/jpeg;base64,' },  
    { label: '', url: 'data:image/jpeg;base64,' }, 
    { label: '', url: 'data:image/jpeg;base64,' },   
    { label: '', url: 'data:image/jpeg;base64,' },   
  ];

  placedItems: any[] = [];

  dragImage: any = null; 

  onDragStart(img: any) {
    this.dragImage = img; //определяем что конкретно тащим
  }


  onDrop(event: any, tierLabel: string) {
    event.preventDefault(); //браузер не откроет картинку
    if (this.dragImage) {
      this.placedItems.push({
        id: Date.now(),
        tierId: tierLabel,
        url: this.dragImage.url,
        label: this.dragImage.label
      });
      this.dragImage = null;
    }
  }

  //получить картинки в ряду
  getItemsByTier(tierLabel: string) {
    return this.placedItems.filter(item => item.tierId === tierLabel);
  }

  removeItem(itemId: number) {
    this.placedItems = this.placedItems.filter(item => item.id !== itemId);
  }

 downloadImage()
 {
  const input = document.createElement('input'); //ivis comp for choice file
  input.type = 'file';
  input.accept= 'image/*';
  input.onchange = (event: any)=> 
  { const file = event.target.files[0]; 
    if (file) {
      const reader = new FileReader(); //create reader
      reader.onload = (e: any)=>{ //onload ready upload event
        const newImage = {
          label: 'ur image',
          url: e.target.result
        };
        this.sourceImages.push(newImage);
      }
      reader.readAsDataURL(file); 
    }   

  };
  input.click() //окно выбора файла
 }



async saveAsImage() {
  const element = document.querySelector('.tiers-container'); //return
  if (!element) {
    console.log('контейнер не обнаружен');
    return;
  }
  
  try {
    const canvas = await html2canvas(element as HTMLElement, {
      scale: 2, 
      backgroundColor: '#151524'
    });
    
    //скачивание
    const link = document.createElement('a');
    link.download = 'tier-list.png';
    link.href = canvas.toDataURL(); //нажатие на link авто
    link.click();
  } catch (error) {
    console.error('ошибка', error);
  }
}

  constructor(private translate: TranslateService) { }

  ngOnInit() {}

}
